INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-census', 'Poverty in the United States: 2023', 'U.S. Census Bureau', 'https://www.census.gov/library/publications/2024/demo/p60-283.html', 2024, 'Current Population Survey ASEC estimates. The official and supplemental poverty measures produce different levels, but the Black–white child poverty gap is stable across both measures and across decades.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-sharkey', 'Stuck in Place: Urban Neighborhoods and the End of Progress toward Racial Equality', 'University of Chicago Press (Patrick Sharkey)', 'https://press.uchicago.edu/ucp/books/book/chicago/S/bo14365260.html', 2013, 'Longitudinal analysis of the Panel Study of Income Dynamics, following families across generations. “High-poverty neighborhood” means a census tract with a poverty rate of 20% or more.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-ocr', 'Civil Rights Data Collection: School Discipline', 'U.S. Department of Education, Office for Civil Rights', 'https://ocrdata.ed.gov/', 2021, 'Administrative data reported by nearly every U.S. public school. It records discipline events, not underlying behavior — but studies that control for the type of infraction still find Black students disciplined more harshly for similar conduct.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-csg', 'Breaking Schools’ Rules: A Statewide Study of How School Discipline Relates to Students’ Success', 'Council of State Governments Justice Center', 'https://csgjusticecenter.org/publications/breaking-schools-rules/', 2011, 'Cohort study of nearly one million Texas students followed for six years, controlling for 83 student and campus variables. Correlational: it cannot fully rule out unobserved differences, but the controls are unusually extensive.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-sentencing-project', 'Report to the United Nations on Racial Disparities in the U.S. Criminal Justice System', 'The Sentencing Project', 'https://www.sentencingproject.org/reports/report-to-the-united-nations-on-racial-disparities-in-the-u-s-criminal-justice-system/', 2018, 'Synthesis of FBI Uniform Crime Reporting and Bureau of Justice Statistics data. Arrest-rate ratios reflect police contact, which is shaped by deployment and enforcement priorities as well as by offending.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-stanford', 'A large-scale analysis of racial disparities in police stops across the United States', 'Nature Human Behaviour (Stanford Open Policing Project)', 'https://www.nature.com/articles/s41562-020-0858-1', 2020, 'Analysis of nearly 100 million traffic stops. Search “hit rates” were lower for Black drivers than white drivers — evidence that the bar for searching Black drivers was lower, not that offending was higher.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-berdejo', 'Criminalizing Race: Racial Disparities in Plea-Bargaining', 'Boston College Law Review (Carlos Berdejó)', 'https://lawdigitalcommons.bc.edu/bclr/vol59/iss4/2/', 2018, 'Analysis of every case filed in Wisconsin circuit courts over seven years — roughly 30,000 cases — comparing defendants facing the same initial charge with no prior record. Single-state data; the direction of the finding is consistent with multi-state studies.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-rehavi-starr', 'Racial Disparity in Federal Criminal Sentences', 'Journal of Political Economy (M. Marit Rehavi & Sonja B. Starr)', 'https://www.journals.uchicago.edu/doi/10.1086/677255', 2014, 'Links federal cases from arrest through sentencing, controlling for arrest offense and criminal history. Roughly half of the remaining sentence gap is explained by prosecutors’ initial charging decisions — especially charges carrying mandatory minimums.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-dobbie', 'The Effects of Pre-Trial Detention on Conviction, Future Crime, and Employment', 'American Economic Review (Dobbie, Goldin & Yang)', 'https://www.aeaweb.org/articles?id=10.1257/aer.20161503', 2018, 'Quasi-experimental design exploiting the effectively random assignment of bail judges. The conviction effect is driven almost entirely by increased guilty pleas among detained defendants.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-bjs-prevalence', 'Prevalence of Imprisonment in the U.S. Population, 1974–2001', 'Bureau of Justice Statistics (Thomas P. Bonczar)', 'https://bjs.ojp.gov/library/publications/prevalence-imprisonment-us-population-1974-2001', 2003, 'Lifetime-likelihood projection based on 2001 incarceration rates. Incarceration has declined since, so the realized rate for the 2001 birth cohort will be lower than projected — the racial disparity ratio, however, has persisted.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-bjs-recidivism', 'Recidivism of Prisoners Released: 5-Year Follow-Up Studies', 'Bureau of Justice Statistics', 'https://bjs.ojp.gov/library/publications/recidivism-prisoners-released-34-states-2012-5-year-follow-period-2012-2017', 2021, 'Five-year rearrest rates range from roughly 68% to 77% across BJS release cohorts. Rearrest is not reconviction: it measures renewed police contact, which is itself shaped by supervision intensity and policing patterns.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-pager', 'The Mark of a Criminal Record', 'American Journal of Sociology (Devah Pager)', 'https://www.journals.uchicago.edu/doi/10.1086/374403', 2003, 'Matched-pair audit study using trained testers with identical résumés in Milwaukee. Replicated in New York City in 2004 with consistent results. Audit studies measure employer behavior directly rather than inferring it from surveys.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-ppi', 'Out of Prison & Out of Work: Unemployment among formerly incarcerated people', 'Prison Policy Initiative', 'https://www.prisonpolicy.org/reports/outofwork.html', 2018, 'Based on the National Former Prisoner Survey (2008) — the most recent national estimate available. The 27% unemployment rate exceeds the overall U.S. rate at any point in history, including the Great Depression.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-aecf', 'A Shared Sentence: The Devastating Toll of Parental Incarceration on Kids, Families and Communities', 'The Annie E. Casey Foundation', 'https://www.aecf.org/resources/a-shared-sentence', 2016, 'Cumulative childhood prevalence estimated from the National Survey of Children’s Health. Measures whether a child has ever had a resident parent incarcerated, not current incarceration.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-rand', 'Evaluating the Effectiveness of Correctional Education', 'RAND Corporation', 'https://www.rand.org/pubs/research_reports/RR266.html', 2013, 'Meta-analysis of 30 years of correctional-education studies commissioned by the U.S. Department of Justice. The 43% figure is reduced odds of recidivating among participants; selection into programs is a known limitation the study weights for.');
INSERT OR REPLACE INTO sources (id, title, publisher, url, year, methodology_note) VALUES ('src-ussc', 'Demographic Differences in Sentencing', 'U.S. Sentencing Commission', 'https://www.ussc.gov/research/research-reports/demographic-differences-sentencing', 2023, 'Multivariate regression of federal sentences controlling for guideline factors. The Commission’s estimated Black–white sentence gap for similarly situated men has ranged from about 10% to 20% across report periods and specifications.');

INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a1-poverty', 1, 'black-child-poverty', 'Black child poverty rate', '28.5%', 'Roughly 28.5% of Black children in the United States live below the poverty line — nearly three times the rate for white children.', 'src-census', 'Poverty measures vary (official vs. supplemental) and shift year to year. The roughly 3-to-1 gap between Black and white child poverty is stable across measures and across decades.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a1-neighborhood', 1, 'neighborhood-poverty', 'raised in high-poverty neighborhoods', '66% vs 6%', 'Two-thirds of Black children raised between 1985 and 2000 grew up in high-poverty neighborhoods. For white children: about 6%.', 'src-sharkey', '“High-poverty” means a census tract with a 20%+ poverty rate. The estimate comes from the PSID, a longitudinal panel — it tracks the same families for decades, but panels can underrepresent the most transient households.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a2-suspension', 2, 'suspension-disparity', 'more likely to be suspended', '3.6×', 'Black students are 3.6 times more likely than white students to receive one or more out-of-school suspensions. The gap appears as early as preschool.', 'src-ocr', 'Administrative data records discipline events, not behavior. But studies that control for the specific infraction still find Black students punished more severely for similar conduct — the gap is largest for subjective offenses like “defiance.”', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a2-pipeline', 2, 'suspension-to-justice', 'more likely to touch the justice system after suspension', '2.85×', 'Students suspended or expelled for a discretionary violation were nearly three times more likely to be in contact with the juvenile justice system the following year.', 'src-csg', 'Correlational cohort study of nearly one million Texas students with 83 controls. It cannot fully rule out selection effects — but the discretionary/non-discretionary comparison is designed to isolate the school’s choice.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a3-arrest', 3, 'arrest-disparity', 'more likely to be arrested', '2.8×', 'Black Americans are arrested at roughly 2.8 times the rate of white Americans.', 'src-sentencing-project', 'Arrest rates measure police contact, not just offending. Self-report surveys show much smaller racial differences in underlying behavior for common offenses — especially drug offenses, where use rates are similar.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a3-search', 3, 'search-disparity', 'more likely to be searched at a traffic stop', '~2×', 'Across nearly 100 million analyzed traffic stops, Black drivers were stopped more often and searched at roughly twice the rate of white drivers.', 'src-stanford', 'The study’s key check: searches of Black drivers turned up contraband less often. A lower “hit rate” means the evidentiary bar for searching Black drivers was lower — the disparity is in the standard applied, not the behavior found.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a4-charge-reduction', 4, 'plea-charge-reduction', 'chance the top charge gets reduced or dropped', '63.9% vs 50.7%', 'Among defendants facing the same initial charge with no prior record, white defendants had their most serious charge reduced or dropped 63.9% of the time. Black defendants: 50.7% — a 25% relative gap.', 'src-berdejo', 'Wisconsin circuit-court data (~30,000 cases over seven years). Single-state, but one of the only datasets that observes the initial charge, the final charge, and prior record together.', 'fork');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a4-misdemeanor', 4, 'plea-misdemeanor-jail', 'more often avoids a jail-carrying conviction (same misdemeanor)', '75%', 'In misdemeanor cases, white defendants were roughly 75% more likely than Black defendants to be convicted of nothing that carried possible incarceration — or nothing at all.', 'src-berdejo', 'Same Wisconsin dataset as the charge-reduction figure. The gap is largest precisely where prosecutors have the most discretion and the least information: low-level first offenses.', 'fork');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a4-sentence', 4, 'plea-sentence-length', 'longer federal sentences for the same arrest offense', '~10%', 'Conditional on the same arrest offense and criminal history, Black men receive federal sentences roughly 10% longer than white men. About half the gap traces to prosecutors’ initial charging decisions.', 'src-rehavi-starr', 'Federal cases only; state systems vary. The U.S. Sentencing Commission’s own regressions have estimated gaps between about 10% and 20% depending on period and specification.', 'fork');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a4-detention', 4, 'pretrial-detention-conviction', 'higher chance of conviction when detained pretrial', '+13%', 'Being detained before trial — usually for inability to pay bail — raises the likelihood of conviction by about 13 percentage points, driven almost entirely by guilty pleas.', 'src-dobbie', 'Quasi-experimental: uses the random assignment of bail judges as a natural experiment, so the effect is causal for marginal cases, not a simple correlation.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a5-lifetime', 5, 'lifetime-imprisonment', 'Black boys born in 2001 projected to be imprisoned in their lifetime', '1 in 3', 'At the incarceration rates of 2001 — the year Deon was born — 1 in 3 Black boys could expect to be imprisoned in his lifetime. For white boys: 1 in 17.', 'src-bjs-prevalence', 'A projection from 2001 rates, not a measured outcome. Incarceration has fallen since, so the realized number for this cohort will be lower — the disparity ratio between the two projections has persisted.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a5-mandmin', 5, 'mandatory-minimum', 'more likely to be charged with a mandatory-minimum offense', '1.75×', 'For the same underlying arrest conduct, federal prosecutors were 1.75 times more likely to file charges carrying a mandatory minimum sentence against Black defendants.', 'src-rehavi-starr', 'Controls for arrest offense, criminal history, district, and demographics. Charging is where the discretion lives: the mandatory minimum is chosen before any judge is involved.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a5-recidivism', 5, 'five-year-rearrest', 'of released prisoners rearrested within five years', '72.7%', 'Roughly seven in ten people released from state prison are rearrested within five years. The system Deon leaves is engineered to receive him back.', 'src-bjs-recidivism', 'Rearrest, not reconviction — it measures renewed police contact. Five-year rearrest ranges from about 68% to 77% across BJS release cohorts; supervision intensity itself generates arrests (technical violations).', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a6-callback', 6, 'callback-rate', 'callback rate: Black applicant with a record', '5%', 'In matched-pair hiring audits, white applicants WITH a felony record were called back 17% of the time — more often than Black applicants WITHOUT one (14%). Black applicants with a record: 5%.', 'src-pager', 'Milwaukee, 2001, entry-level jobs, trained testers with identical résumés. Replicated in New York City in 2004 with the same pattern. Audit studies measure what employers do, not what they say.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a6-unemployment', 6, 'formerly-incarcerated-unemployment', 'unemployment among formerly incarcerated people', '27%', 'Higher than the U.S. unemployment rate at any point in recorded history, including the Great Depression. For formerly incarcerated Black women: 43.6%.', 'src-ppi', 'Based on the 2008 National Former Prisoner Survey — the most recent national estimate. Counts only people actively looking for work; discouraged non-seekers are excluded from both numerator and denominator.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a7-parent', 7, 'parental-incarceration', 'Black children who have had a parent incarcerated', '1 in 9', 'One in nine Black children has had a parent behind bars. The record does not stop at the person it names.', 'src-aecf', 'Cumulative childhood prevalence from the National Survey of Children’s Health — whether a resident parent was ever incarcerated, not a point-in-time count.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-a7-education', 7, 'correctional-education', 'lower odds of returning to prison with correctional education', '43%', 'People who participate in education programs while incarcerated have 43% lower odds of recidivating. The single most reliable lever the data offers is also the quietest one.', 'src-rand', 'Meta-analysis of 30 years of studies. Selection is the known limitation — people who enroll differ from people who don’t — and the analysis weights study quality to account for it.', 'card');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-cl-poverty', 0, 'compare-poverty', 'childhood below the poverty line', '≈3×', 'Black children are nearly three times more likely than white children to grow up below the poverty line, and eleven times more likely to grow up in a high-poverty neighborhood.', 'src-census', 'Poverty is a structural exposure, not a behavior. These figures describe the distribution of childhood conditions, not any individual family.', 'calculator');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-cl-discipline', 0, 'compare-discipline', 'school discipline exposure', '2.85×', 'A discretionary suspension nearly triples the odds of juvenile-justice contact within a year — and Black students are 3.6× more likely to be suspended in the first place.', 'src-csg', 'The Texas cohort study controls for 83 variables but remains correlational. The 3.6× suspension disparity is national administrative data.', 'calculator');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-cl-bail', 0, 'compare-bail', 'pretrial detention effect', '+13%', 'Defendants who cannot afford bail are about 13 percentage points more likely to be convicted — almost entirely through guilty pleas — and suffer lasting employment losses.', 'src-dobbie', 'Causal estimate from random judge assignment. The mechanism is leverage: detention makes pleading out the fastest way home.', 'calculator');
INSERT OR REPLACE INTO statistics (id, act_number, slug, short_claim, value_text, detail_text, source_id, skeptic_caveat, display_style) VALUES ('st-cl-charge', 0, 'compare-charge', 'felony record employment penalty', '5% vs 17%', 'A felony record cuts a Black applicant’s callback rate to 5% — less than a third of the rate for a white applicant with the identical record (17%).', 'src-pager', 'Matched-pair audit data. For misdemeanors, the plea-bargaining stage is where the disparity concentrates: white defendants avoid jail-carrying convictions ~75% more often.', 'calculator');

INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-1', 1, 'before-he-has-a-name', 'Before He Has a Name', '2001', 'The boy was called Deon. He was born in 2001, in an apartment on the north side of a city that looked like a lot of American cities — old industry, new neglect, neighborhoods where the map turns gray.

His grandmother called him watchful. She meant it as a compliment.

He watched everything from the window of the apartment where four people lived in three rooms. He watched the block below, which was beautiful and dangerous in the way that blocks like that are always both.

Nothing about him was decided yet. That is the thing to hold onto. He was a baby in a blanket with a name his mother chose because it sounded like a bell.

But a file had already been opened. Not on him — around him. The census tract. The school zone. The distance to the nearest grocery store, and the shorter distance to the nearest precinct. The odds were assembled before he had a name.', 0.1, '/media/scenes/before-he-has-a-name.mp4', '/media/posters/before-he-has-a-name.jpg', NULL, 'dark');
INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-2', 2, 'the-hallway', 'The Hallway', '2013 — seventh grade', 'The first time the system wrote Deon’s name down, he was twelve. He had pushed a boy who had pushed him first. Both things were true; only one was recorded.

The suspension was three days. His mother took an unpaid shift off to sit across from a vice principal who kept saying the word “pattern” about a child who had no pattern.

Deon was not suspended because he was worse than other boys. The data is blunt about this: he was suspended because of how the same behavior gets read on different children.

Three days is not long. But a discipline file is a door, and doors like that open in one direction. The next hallway incident would not start from zero. Nothing in his life would start from zero again.', 0.1, '/media/scenes/the-hallway.mp4', '/media/posters/the-hallway.jpg', NULL, 'dark');
INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-3', 3, 'the-stop', 'The Stop', '2019 — nineteen years old', 'It was a Tuesday in June and the tail light was out. That part is not in dispute.

Deon was nineteen, driving his cousin’s car to a job interview — a warehouse, second shift, twelve dollars an hour. He had printed his résumé at the library. It was on the passenger seat when the lights came on behind him.

The stop took forty minutes. The search took ten. The bag under the passenger seat was his cousin’s; the arrest was his. A first arrest, at nineteen, with a résumé on the seat.

He did what the data says happens: he became a number in the column where boys like him are 2.8 times more likely to appear. Not because the numbers know him. Because the system that produced the numbers had already met a thousand boys it decided were him.', 0.1, '/media/scenes/the-stop.mp4', '/media/posters/the-stop.jpg', NULL, 'dark');
INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-4', 4, 'the-plea', 'The Plea', 'The same mistake', 'The public defender had eleven minutes. She was good — tired-good, the way people are good at jobs designed to be impossible. She laid out the arithmetic: fight it and risk years, or take the deal and take the record.

Deon could not afford bail. He had been inside for nineteen days, and the warehouse job was gone, and every day inside made the deal look more like a door.

Here the story has to stop being one story. Because somewhere in the same state, in the same June, a boy the same age with the same charge and the same empty record sat in a different room — out on bail his parents posted — and the arithmetic ran differently.

Same mistake. Different math. The fork below is not a metaphor. It is measured.', 0.1, '/media/scenes/the-plea.mp4', '/media/posters/the-plea.jpg', NULL, 'dark');
INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-5', 5, 'the-count', 'The Count', 'Thirty-one months', 'Time moves differently inside. That is not a saying; it is a policy. The count happens four times a day, and between counts, time is something done to you.

Deon was one of the 1 in 3 — the projection published two years after he was born, as if the state had drafted a schedule for him and then waited.

He read. There was a class, sometimes, when there was funding, which was sometimes. He wrote letters to his mother in handwriting that got smaller every month, as if he were making himself easier to store.

The walls here are not a metaphor either. The scroll slows down because he cannot make it go faster. Neither can you.', 0.03, '/media/scenes/the-count.mp4', '/media/posters/the-count.jpg', NULL, 'desaturated');
INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-6', 6, 'the-box', 'The Box', 'After', 'They give you your shoes back, and a bus ticket, and a paper that proves where you have been to anyone who asks. Everyone asks.

The application at the second warehouse was two pages. The box was on page one, above his name, as if the record were the applicant and Deon the attachment.

Have you ever been convicted of a felony? The box does not ask what happened, or what the public defender had eleven minutes to explain, or what a nineteen-day wait in county does to arithmetic. The box holds one bit of information and it is enough.

He checked it, because lying is a crime and he was done committing those. Then he waited by a phone that the data says would ring for one applicant in twenty who looked like him.', 0.1, '/media/scenes/the-box.mp4', '/media/posters/the-box.jpg', NULL, 'dark');
INSERT OR REPLACE INTO story_acts (id, act_number, slug, title, subtitle, body_mdx, lenis_lerp, higgsfield_loop_url, poster_url, elevenlabs_audio_url, palette) VALUES ('act-7', 7, 'the-nursery', 'The Nursery', '2026', 'The boy was called Marcus. He was born in 2026, in a small apartment with a window, to a father who watched him the way his own grandmother once described: watchful, and meaning it as a compliment.

Deon works nights and studies mornings. The class he started inside became a certificate outside — the one lever the data ever agreed on. The record follows him still. But he is carrying it now, instead of it carrying him.

There is a plant on the windowsill of the nursery. It is small and stubborn and green — the first green thing in this story, which was not an accident of light.

Marcus’s file is empty. Whether it stays that way is not up to Marcus, and it never was. It is up to the systems this story put on trial — and to the people who can still amend them.

He is not born guilty. The record is open. It is still mostly blank. Hold the pen.', 0.1, '/media/scenes/the-nursery.mp4', '/media/posters/the-nursery.jpg', NULL, 'seedling');

INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-1', 'the-ledger', 'The Ledger', 'prologue', 1, 24, '/media/scenes/the-ledger.mp4', '/media/posters/the-ledger.jpg', 'This is a story about a boy who does not exist. His name is Deon. We built him out of numbers — and every number is real. Before he has a name, a ledger is already open: where he will live, what his school will do with him, how a traffic stop will go. This film reads the ledger out loud.', '/media/narration/the-ledger.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A ledger book opening in darkness, pages turning slowly, columns of figures dissolving into a city skyline silhouette at night.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-2', 'before-he-has-a-name', 'Before He Has a Name', 'act-1', 2, 32, '/media/scenes/before-he-has-a-name.mp4', '/media/posters/before-he-has-a-name.jpg', 'Deon is born in 2001, on the north side of a city like a lot of American cities. Four people, three rooms, one window. More than a quarter of Black children in America grow up below the poverty line — nearly three times the rate for white children. Two-thirds grow up in high-poverty neighborhoods. For white children, six percent. Nothing about him is decided yet. But the odds were assembled before he had a name.', '/media/narration/before-he-has-a-name.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A mother holding an infant silhouetted against an apartment window, city block below, streetlight glow, laundry lines, quiet.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-3', 'the-hallway', 'The Hallway', 'act-2', 3, 30, '/media/scenes/the-hallway.mp4', '/media/posters/the-hallway.jpg', 'Seventh grade. A push in a hallway — two boys, both pushed, one recorded. Black students are three point six times more likely to be suspended for the same behavior. And a suspension is a door: students suspended for a discretionary offense are nearly three times more likely to touch the juvenile justice system within a year. Three days out of school. Nothing starts from zero again.', '/media/narration/the-hallway.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A long empty school hallway, lockers in silhouette, a small figure walking away carrying a backpack, fluorescent light pooling.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-4', 'the-stop', 'The Stop', 'act-3', 4, 25, '/media/scenes/the-stop.mp4', '/media/posters/the-stop.jpg', 'Nineteen years old. A tail light. A résumé on the passenger seat. Black drivers are searched at roughly twice the rate of white drivers — and the searches find less. Black Americans are arrested at two point eight times the rate of white Americans. The stop takes forty minutes. The interview never happens.', '/media/narration/the-stop.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A car at night pulled to a curb, headlight beams and long shadows, a paper résumé on a passenger seat, red glow kept off-screen.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-5', 'the-plea', 'The Plea', 'act-4', 5, 38, '/media/scenes/the-plea.mp4', '/media/posters/the-plea.jpg', 'Two boys. Same age. Same charge. No priors. The white defendant’s top charge is reduced or dropped sixty-three point nine percent of the time. The Black defendant’s: fifty point seven. For the same misdemeanor, the white defendant avoids a jail-carrying conviction seventy-five percent more often. Deon cannot afford bail — and detention raises conviction by thirteen points, almost entirely through guilty pleas. He takes the deal. The same mistake was never the same mistake.', '/media/narration/the-plea.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A table splitting the frame in two, two identical silhouetted figures on either side, one door opening and one staying shut, scales implied by light.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-6', 'the-count', 'The Count', 'act-5', 6, 33, '/media/scenes/the-count.mp4', '/media/posters/the-count.jpg', 'Thirty-one months. The count happens four times a day. One in three Black boys born in 2001 was projected to be imprisoned in his lifetime; for white boys, one in seventeen. For the same conduct, prosecutors file mandatory-minimum charges one point seven five times more often against Black defendants. Deon reads. There is a class, when there is funding. Time is something done to him.', '/media/narration/the-count.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: Slow pan across a cell block in silhouette, bars casting long parallel shadows, a single figure reading by a small light, desaturated.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-7', 'the-box', 'The Box', 'act-6', 7, 32, '/media/scenes/the-box.mp4', '/media/posters/the-box.jpg', 'They give you your shoes, a bus ticket, and a record. The application asks one question in a box above his name. In matched audits, a white applicant with a felony record gets called back more often than a Black applicant with no record at all. A Black applicant with a record: five percent. Unemployment among the formerly incarcerated is twenty-seven percent — worse than the Great Depression. Deon checks the box, because it is the truth.', '/media/narration/the-box.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A pen hovering over a printed form, an oversized checkbox, a phone on a table that does not ring, window light crossing the frame.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');
INSERT OR REPLACE INTO video_scenes (id, slug, title, chapter_slug, sequence, duration_seconds, video_url, poster_url, transcript_text, narration_audio_url, higgsfield_prompt, elevenlabs_voice_id, status) VALUES ('vs-8', 'the-nursery', 'The Nursery', 'act-7', 8, 37, '/media/scenes/the-nursery.mp4', '/media/posters/the-nursery.jpg', 'Twenty twenty-six. A boy named Marcus is born to a father who is watchful, and means it as a compliment. The class Deon started inside became a certificate outside: education in prison cuts the odds of going back by forty-three percent. One in nine Black children has had a parent behind bars — the record follows families. But Marcus’s file is empty. It is still mostly blank. This is the only scene with color in it. Hold the pen.', '/media/narration/the-nursery.mp3', 'Hand-drawn pen and ink illustration animation on aged cream sketchbook paper with worn edges, vintage archival documentary style, crosshatched pen shading, figures rendered as bold solid black ink silhouettes — Black subjects portrayed with dignity and tenderness, never caricature — subtle animated line work, slow gentle camera drift, quiet, humane. No photorealism, no bright colors, no violence, no readable words or lettering. Scene: A nursery at dawn, a father silhouetted holding an infant by a window, a small potted seedling on the sill rendered in muted green — the only color in the film.', 'dc382508-c8bd-443c-8cb2-46e57b8d2e6f', 'ready');

